					return in_array( $size, $sizes_enabled, true );
				} )

array_filter( $optimized_sizes, function( $size ) use ( $sizes_enabled ) {
					return in_array( $size, $sizes_enabled, true );
				} )

array_filter($size_keys, function( string $size ) use ( $enabled_sizes ) {
			if ( Image::SIZE_FULL === $size ) {
				return true;
			}

			if ( in_array( $size, $enabled_sizes, true ) ) {
				return true;
			}

			return false;
		})

